const processType = {{workflowparams:process_type}} || "";
const items = {{workflowparams:items}} || [];
const sourceHu = {{workflowparams:source_hu}} || null;
const targetHu = {{workflowparams:target_hu}} || null;
const targetWarehouseLocationId = {{workflowparams:target_location_id}} || "";
const targetWarehouseStorageLocationId = {{workflowparams:target_storage_location_id}} || "";
const remark = {{workflowparams:remark}} || "";

// Source variant keeps the item's original bin — used for unload from source HU.
const tableHuItems = items.map((it) => ({
  material_id: it.material_id,
  material_name: it.material_name,
  material_desc: it.material_desc,
  location_id: it.location_id,
  batch_id: it.batch_id || null,
  material_uom: it.material_uom,
  quantity: parseFloat(it.quantity) || 0,
  balance_id: it.balance_id || "",
}));

// Target variant pins items to the target HU's bin — on load, items sit
// inside the new HU at the target location, not the source bin they came from.
const targetItemsLocationId = (targetHu && targetHu.location_id) || targetWarehouseLocationId || "";
const tableHuItemsTarget = items.map((it) => ({
  material_id: it.material_id,
  material_name: it.material_name,
  material_desc: it.material_desc,
  location_id: targetItemsLocationId,
  batch_id: it.batch_id || null,
  material_uom: it.material_uom,
  quantity: parseFloat(it.quantity) || 0,
  balance_id: it.balance_id || "",
}));

const targetIsNew =
  (processType === "Load" || processType === "Transfer") &&
  targetHu &&
  !targetHu.id &&
  targetHu.handling_no === "Auto-generated number";

const needsSourceUnload = processType === "Unload" || processType === "Transfer";
const needsTargetLoad = processType === "Load" || processType === "Transfer";

return {
  processType,
  items,
  tableHuItems,
  tableHuItemsTarget,
  sourceHu,
  targetHu,
  targetWarehouseLocationId,
  targetWarehouseStorageLocationId,
  remark,
  targetIsNew: targetIsNew ? 1 : 0,
  needsSourceUnload: needsSourceUnload ? 1 : 0,
  needsTargetLoad: needsTargetLoad ? 1 : 0,
  isPacking: {{workflowparams:isPacking}} || 0
};

const ctx = {{node:code_node_CPgy5sGX.data}};
const targetIsNew = ctx.targetIsNew === 1;

let resolvedTargetHuId = "";
if (targetIsNew) {
  const huResult = {{node:workflow_node_5c85PxTg.data}} || {};
  resolvedTargetHuId = huResult.huId || huResult.id || "";
} else {
  resolvedTargetHuId = ctx.targetHu?.id || "";
}

return { resolvedTargetHuId };

const ctx = {{node:code_node_CPgy5sGX.data}};
const resolvedTargetHuId = {{node:code_node_KA3mv0Kd.data.resolvedTargetHuId}} || "";
const item = {{node:loop_UsaBEWcU}};
const processType = ctx.processType;
const sourceHu = ctx.sourceHu;

let subtractLocationId = "";
let subtractHandlingUnitId = "";
let addLocationId = "";
let addHandlingUnitId = "";

if (processType === "Load") {
  subtractLocationId = item.location_id;
  subtractHandlingUnitId = "";
  addLocationId = ctx.targetHu?.location_id || "";
  addHandlingUnitId = resolvedTargetHuId;
} else if (processType === "Unload") {
  subtractLocationId = item.location_id;
  subtractHandlingUnitId = sourceHu?.id || "";
  addLocationId = ctx.targetWarehouseLocationId;
  addHandlingUnitId = "";
} else if (processType === "Transfer") {
  subtractLocationId = item.location_id;
  subtractHandlingUnitId = sourceHu?.id || "";
  addLocationId = ctx.targetHu?.location_id || "";
  addHandlingUnitId = resolvedTargetHuId;
}

return {
  material_id: item.material_id,
  material_uom: item.material_uom,
  quantity: parseFloat(item.quantity) || 0,
  batch_id: item.batch_id || null,
  subtractLocationId,
  subtractHandlingUnitId,
  addLocationId,
  addHandlingUnitId,
};

let huId
let huNo
const unload = {{node:code_node_CPgy5sGX.data.needsSourceUnload}} || 0
const load = {{node:code_node_CPgy5sGX.data.needsTargetLoad}} || 0

if (unload === 1 && load === 0) {
  huId = {{node:workflow_node_sxd7zvXQ.data.huId}} || "";
  huNo = {{node:workflow_node_sxd7zvXQ.data.huNo}} || "";
}

if (unload === 0 && load === 1) {
  huId = {{node:workflow_node_5c85PxTg.data.huId}} || "";
  huNo = {{node:workflow_node_5c85PxTg.data.huNo}} || "";
}

return {
  huId,
  huNo
}
